                  </div>
                </div>
                <span className="text-[10px] font-bold text-green-600 bg-green-50 px-2 py-1 rounded-lg uppercase tracking-widest">Active</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

