import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { 
  LayoutDashboard, Users, Activity, History, CreditCard, Settings, LogOut, CheckCircle, XCircle, Wallet, Share2
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export default function AdminPanel() {
  const { user, profile, signOut, refreshProfile } = useAuthStore();
  const { addToast } = useGameStore();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [renderError, setRenderError] = useState<string | null>(null);
  const [appSettings, setAppSettings] = useState({ upi_id: '', referral_deposit_bonus_percent: 10, referral_bet_loss_bonus_percent: 5 });

  if (renderError) {
    return (
      <div className="min-h-screen bg-red-950 flex items-center justify-center p-4 text-white">
        <div className="bg-red-900/20 border border-red-500 p-8 rounded-2xl max-w-lg w-full">
          <h1 className="text-xl font-bold mb-4">Admin Panel Crash Detected</h1>
          <pre className="bg-black/50 p-4 rounded-lg text-xs font-mono overflow-auto mb-4">{renderError}</pre>
          <button onClick={() => window.location.reload()} className="w-full bg-red-600 py-2 rounded-lg font-bold">RELOAD SYSTEM</button>
        </div>
      </div>
    );
  }

  const [stats, setStats] = useState({
    totalUsers: 0,
    activeRounds: 5,
    totalBetsToday: 0,
    houseProfit: 0,
    totalRevenue: 0,
    totalReferralPaid: 0
  });

  const [users, setUsers] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [referralEarnings, setReferralEarnings] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (profile?.is_admin) {
      fetchDashboardData();
    }
  }, [profile]);

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
      const { data: txs } = await supabase.from('transactions').select('*').gte('created_at', new Date(Date.now() - 86400000).toISOString());
      const { data: allEarnings } = await supabase.from('referral_earnings').select('amount');

      let profit = 0;
      let revenue = 0;
      if (txs) {
        txs.forEach(tx => {
          if (tx.type === 'loss') profit += Number(tx.amount);
          if (tx.type === 'win') profit -= Number(tx.amount);
          if (tx.type === 'deposit' && tx.status === 'completed') revenue += Number(tx.amount);
        });
      }

      setStats({
        totalUsers: userCount || 0,
        activeRounds: 5,
        totalBetsToday: txs?.filter(t => t.type === 'bet').length || 0,
        houseProfit: profit,
        totalRevenue: revenue,
        totalReferralPaid: allEarnings?.reduce((sum, e) => sum + Number(e.amount), 0) || 0
      });

      const { data: userData } = await supabase.from('profiles').select('*').order('created_at', { ascending: false }).limit(50);
      if (userData) setUsers(userData);

      const { data: txData } = await supabase.from('transactions').select('*').order('created_at', { ascending: false }).limit(50);
      if (txData) setTransactions(txData);

      const { data: refData } = await supabase.from('referral_earnings').select('*, referrer:referrer_id(username), referred:referred_user_id(username)').order('created_at', { ascending: false }).limit(50);
      if (refData) setReferralEarnings(refData);

      const { data: settingsData } = await supabase.from('app_settings').select('*').eq('id', 1).single();
      if (settingsData) setAppSettings({ 
        upi_id: settingsData.upi_id || '',
        referral_deposit_bonus_percent: settingsData.referral_deposit_bonus_percent,
        referral_bet_loss_bonus_percent: settingsData.referral_bet_loss_bonus_percent
      });

    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleProcessWithdrawal = async (txId: string, approve: boolean) => {
    try {
      const { error } = await supabase.rpc('admin_process_withdrawal', { p_transaction_id: txId, p_approve: approve });
      if (error) throw error;
      addToast('success', `Withdrawal ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleProcessDeposit = async (txId: string, approve: boolean) => {
    const reason = approve ? '' : prompt('Reason for rejection:');
    if (!approve && reason === null) return;
    try {
      const { error } = await supabase.rpc('admin_process_deposit', { p_transaction_id: txId, p_approve: approve, p_reason: reason || null });
      if (error) throw error;
      addToast('success', `Deposit ${approve ? 'approved' : 'rejected'}`);
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleSaveSettings = async () => {
    try {
      const { error } = await supabase.from('app_settings').update(appSettings).eq('id', 1);
      if (error) throw error;
      addToast('success', 'Settings saved');
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleEditBalance = async (userId: string, currentBalance: number) => {
    const newBal = prompt('Enter new balance:', currentBalance.toString());
    if (!newBal) return;
    try {
      const { error } = await supabase.rpc('admin_edit_balance', { p_target_user_id: userId, p_new_balance: Number(newBal), p_reason: 'Admin Adjustment' });
      if (error) throw error;
      addToast('success', 'Balance updated');
      fetchDashboardData();
    } catch (err: any) { addToast('error', err.message); }
  };

  const handleForceResult = async (sessionType: string) => {
    const num = prompt(`Force result for ${sessionType}\nNumber (0-9):`);
    if (num === null) return;
    const parsedNum = parseInt(num);
    if (isNaN(parsedNum) || parsedNum < 0 || parsedNum > 9) { addToast('error', 'Invalid number'); return; }
    const color = (parsedNum === 0 || parsedNum === 5) ? (parsedNum === 0 ? 'red-violet' : 'green-violet') : ([1,3,7,9].includes(parsedNum) ? 'green' : 'red');
    const bsChoice = prompt(`Calculated: ${parsedNum >= 5 ? 'Big' : 'Small'}\nEnter B/S to override:`);
    let bigSmall = parsedNum >= 5 ? 'Big' : 'Small';
    if (bsChoice?.toUpperCase() === 'B') bigSmall = 'Big';
    if (bsChoice?.toUpperCase() === 'S') bigSmall = 'Small';
    const currentPeriod = useGameStore.getState().sessions[sessionType as any].period;
    try {
      const { error } = await supabase.rpc('admin_force_result', { p_session_type: sessionType, p_period: currentPeriod, p_number: parsedNum, p_color: color, p_big_small: bigSmall });
      if (error) throw error;
      addToast('success', `Forced: ${parsedNum} (${bigSmall})`);
    } catch (err: any) { addToast('error', err.message); }
  };

  const chartData = [
    { name: 'Mon', profit: 4000 }, { name: 'Tue', profit: 3000 }, { name: 'Wed', profit: 5000 },
    { name: 'Thu', profit: 2780 }, { name: 'Fri', profit: 8890 }, { name: 'Sat', profit: 6390 },
    { name: 'Sun', profit: stats.houseProfit },
  ];

  if (!profile) return null;
  if (!profile.is_admin) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
        <div className="bg-gray-900 border border-red-900/50 p-10 rounded-[2rem] text-center max-w-sm w-full shadow-2xl">
          <XCircle className="w-20 h-20 text-red-600 mx-auto mb-6" />
          <h1 className="text-3xl font-black text-white mb-2 italic">ACCESS DENIED</h1>
          <button onClick={() => window.location.href = '/'} className="w-full bg-red-600 text-white font-bold py-4 rounded-2xl mt-4">RETURN TO GAME</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex text-gray-900 font-sans">
      {/* Sidebar */}
      <div className="w-64 bg-gray-900 text-white flex flex-col fixed h-full shadow-2xl z-20">
        <div className="p-6 flex items-center gap-3 border-b border-gray-800">
          <div className="bg-red-600 text-white font-black text-xl w-10 h-10 flex items-center justify-center rounded-xl">66</div>
          <span className="font-bold text-xl uppercase italic tracking-tighter">Admin Panel</span>
        </div>
        <nav className="flex-1 py-6 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'monitor', icon: Activity, label: 'Games Monitor' },
            { id: 'users', icon: Users, label: 'User Control' },
            { id: 'deposits', icon: Wallet, label: 'Deposits' },
            { id: 'referrals', icon: Share2, label: 'Referrals' },
            { id: 'transactions', icon: CreditCard, label: 'Financials' },
            { id: 'settings', icon: Settings, label: 'Settings' },
          ].map((item) => (
            <button key={item.id} onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === item.id ? 'bg-red-600 text-white translate-x-2' : 'text-gray-400 hover:bg-gray-800'}`}>
              <item.icon className="w-5 h-5" /> {item.label}
            </button>
          ))}
        </nav>
        <div className="p-6 border-t border-gray-800">
          <p className="text-sm font-bold text-white truncate mb-4">{profile.username}</p>
          <button onClick={() => { signOut(); window.location.href = '/'; }} className="w-full flex items-center justify-center gap-2 text-xs font-bold text-white bg-red-600/10 border border-red-600/20 py-3 rounded-xl uppercase">
            <LogOut className="w-4 h-4" /> Logout
          </button>
        </div>
      </div>

      {/* Main */}
      <div className="ml-64 flex-1 flex flex-col min-h-screen">
        <header className="bg-white h-20 border-b border-gray-200 flex items-center justify-between px-8 sticky top-0 z-10">
          <h1 className="text-2xl font-black text-gray-800 capitalize italic tracking-tight">{activeTab}</h1>
          <span className="bg-green-100 text-green-700 text-[10px] font-black uppercase px-3 py-1.5 rounded-full border border-green-200 animate-pulse">System Live</span>
        </header>

        <main className="p-8 flex-1 overflow-y-auto">
          {loading ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-400 gap-4 uppercase font-bold text-xs tracking-widest animate-pulse">Syncing...</div>
          ) : (
            <>
              {activeTab === 'dashboard' && (
                <div className="space-y-6">
                  <div className="grid grid-cols-4 gap-6">
                    {[
                      { label: 'Total Users', value: stats.totalUsers, icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' },
                      { label: 'Today\'s Bets', value: stats.totalBetsToday, icon: Activity, color: 'text-orange-600', bg: 'bg-orange-50' },
                      { label: 'House Profit', value: `₹${stats.houseProfit.toLocaleString()}`, icon: CreditCard, color: 'text-red-600', bg: 'bg-red-50' },
                      { label: 'Referral Paid', value: `₹${stats.totalReferralPaid.toLocaleString()}`, icon: Share2, color: 'text-purple-600', bg: 'bg-purple-50' },
                    ].map((s, i) => (
                      <div key={i} className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100 flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${s.bg} ${s.color}`}><s.icon size={24} /></div>
                        <div><p className="text-gray-400 text-[10px] font-black uppercase">{s.label}</p><p className="text-xl font-black">{s.value}</p></div>
                      </div>
                    ))}
                  </div>
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8 h-80">
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                        <XAxis dataKey="name" hide />
                        <Tooltip />
                        <Line type="monotone" dataKey="profit" stroke="#dc2626" strokeWidth={4} dot={{r: 4}} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              )}

              {activeTab === 'deposits' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <table className="w-full text-left text-sm">
                    <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b">
                      <tr><th className="p-6">Date</th><th className="p-6">Account</th><th className="p-6">UTR</th><th className="p-6">Amount</th><th className="p-6 text-right">Action</th></tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {transactions.filter(t => t.type === 'deposit' && t.status === 'pending').map(tx => (
                        <tr key={tx.id}>
                          <td className="p-6 font-bold text-gray-400">{new Date(tx.created_at).toLocaleString()}</td>
                          <td className="p-6 font-mono text-xs">{tx.user_id.substring(0, 12)}</td>
                          <td className="p-6 font-black tracking-widest">{tx.utr}</td>
                          <td className="p-6 font-black text-green-600">₹{Number(tx.amount).toLocaleString()}</td>
                          <td className="p-6 text-right space-x-2">
                            <button onClick={() => handleProcessDeposit(tx.id, true)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase">Approve</button>
                            <button onClick={() => handleProcessDeposit(tx.id, false)} className="bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase">Reject</button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}

              {activeTab === 'referrals' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <table className="w-full text-left text-sm">
                    <thead className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b">
                      <tr><th className="p-6">Date</th><th className="p-6">Referrer</th><th className="p-6">Referred User</th><th className="p-6">Type</th><th className="p-6">Bonus</th></tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {referralEarnings.map(e => (
                        <tr key={e.id}>
                          <td className="p-6 font-bold text-gray-400">{new Date(e.created_at).toLocaleDateString()}</td>
                          <td className="p-6 font-black italic uppercase text-gray-900">{e.referrer?.username}</td>
                          <td className="p-6 font-bold text-gray-500">{e.referred?.username}</td>
                          <td className="p-6 uppercase text-[10px] font-black"><span className={e.from_type === 'deposit' ? 'text-blue-500' : 'text-orange-500'}>{e.from_type}</span></td>
                          <td className="p-6 font-black text-green-600">₹{Number(e.amount).toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}

              {activeTab === 'settings' && (
                <div className="max-w-xl bg-white p-8 rounded-[2rem] shadow-sm border space-y-6 mx-auto">
                  <h3 className="font-black italic uppercase text-lg border-b pb-4">Global Config</h3>
                  <div className="space-y-4">
                    <div>
                      <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">UPI Gateway ID</label>
                      <input type="text" value={appSettings.upi_id} onChange={e => setAppSettings({...appSettings, upi_id: e.target.value})} className="w-full bg-gray-50 border p-4 rounded-2xl font-mono" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Ref Deposit %</label>
                        <input type="number" value={appSettings.referral_deposit_bonus_percent} onChange={e => setAppSettings({...appSettings, referral_deposit_bonus_percent: Number(e.target.value)})} className="w-full bg-gray-50 border p-4 rounded-2xl font-black" />
                      </div>
                      <div>
                        <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Ref Loss %</label>
                        <input type="number" value={appSettings.referral_bet_loss_bonus_percent} onChange={e => setAppSettings({...appSettings, referral_bet_loss_bonus_percent: Number(e.target.value)})} className="w-full bg-gray-50 border p-4 rounded-2xl font-black" />
                      </div>
                    </div>
                    <button onClick={handleSaveSettings} className="w-full bg-red-600 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] shadow-lg">Save Changes</button>
                  </div>
                </div>
              )}
            </>
          )}
        </main>
      </div>
    </div>
  );
}

