      if (refData) setReferralEarnings(refData);

      const { data: settingsData, error: se } = await supabase.from('app_settings').select('*').eq('id', 1).single();
      if (se) console.error('Admin: Settings fetch error:', se);
      if (settingsData) setAppSettings({ 
        upi_id: settingsData.upi_id || '',
