                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50/50 text-gray-400 font-black uppercase tracking-[0.2em] text-[10px] border-b border-gray-100">
                        <tr>
                          <th className="p-6 pl-8">Timestamp</th>
                          <th className="p-6">Account</th>
                          <th className="p-6">UTR</th>
                          <th className="p-6">Amount</th>
                          <th className="p-6 text-right pr-8">Operation</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {transactions.filter(t => t.type === 'deposit' && t.status === 'pending').map(tx => (
                          <tr key={tx.id} className="hover:bg-gray-50/50 transition-colors">
                            <td className="p-6 pl-8 text-gray-400 font-bold text-[10px] uppercase">{new Date(tx.created_at).toLocaleString()}</td>
                            <td className="p-6 font-mono text-[10px] text-gray-400 uppercase">{tx.user_id.substring(0, 12)}</td>
                            <td className="p-6 font-mono font-bold text-gray-900 tracking-wider">{tx.utr}</td>
                            <td className="p-6 font-black text-green-600 text-lg">₹{Number(tx.amount).toLocaleString()}</td>
                            <td className="p-6 text-right pr-8">
                              <div className="flex justify-end gap-2">
                                <button onClick={() => handleProcessDeposit(tx.id, true)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-green-600/20 active:scale-95 transition-all">Approve</button>
                                <button onClick={() => handleProcessDeposit(tx.id, false)} className="bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-600/20 active:scale-95 transition-all">Reject</button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Referrals Tab */}
              {activeTab === 'referrals' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                    <h2 className="text-xl font-black text-gray-800 uppercase italic">Referral Earnings</h2>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50/50 text-gray-400 font-black uppercase tracking-[0.2em] text-[10px] border-b border-gray-100">
                        <tr>
                          <th className="p-6 pl-8">Date</th>
                          <th className="p-6">Referrer</th>
                          <th className="p-6">Subordinate</th>
                          <th className="p-6">Type</th>
                          <th className="p-6">Bonus</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {referralEarnings.map(e => (
                          <tr key={e.id}>
                            <td className="p-6 pl-8 font-bold text-gray-400">{new Date(e.created_at).toLocaleDateString()}</td>
                            <td className="p-6 font-black uppercase italic text-gray-900">{e.referrer?.username}</td>
                            <td className="p-6 font-bold text-gray-500">{e.referred?.username}</td>
                            <td className="p-6 uppercase text-[10px] font-black"><span className={e.from_type === 'deposit' ? 'text-blue-500' : 'text-orange-500'}>{e.from_type}</span></td>
                            <td className="p-6 font-black text-green-600">₹{Number(e.amount).toLocaleString()}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Transactions Tab */}
              {activeTab === 'transactions' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 overflow-hidden">
                  <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                    <h2 className="text-xl font-black text-gray-800 uppercase italic">Financial Stream</h2>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                      <thead className="bg-gray-50/50 text-gray-400 font-black uppercase tracking-[0.2em] text-[10px] border-b border-gray-100">
                        <tr>
                          <th className="p-6 pl-8">Timestamp</th>
                          <th className="p-6">Account</th>
                          <th className="p-6">Flow</th>
                          <th className="p-6">Value</th>
                          <th className="p-6">Audit Status</th>
                          <th className="p-6 text-right pr-8">Operation</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {transactions.map(tx => (
                          <tr key={tx.id} className="hover:bg-gray-50/50 transition-colors">
                            <td className="p-6 pl-8 text-gray-400 font-bold text-[10px] uppercase">{new Date(tx.created_at).toLocaleString()}</td>
                            <td className="p-6 font-mono text-[10px] text-gray-400 uppercase">{tx.user_id.substring(0, 12)}</td>
                            <td className="p-6">
                              <span className="capitalize font-black text-gray-900 italic">{tx.type}</span>
                            </td>
                            <td className="p-6 font-black text-gray-900">₹{Number(tx.amount).toLocaleString()}</td>
                            <td className="p-6">
                              <span className={`flex items-center gap-2 font-black uppercase text-[10px] tracking-tighter ${tx.status === 'completed' ? 'text-green-600' : tx.status === 'pending' ? 'text-orange-500' : 'text-red-600'}`}>
                                {tx.status === 'completed' ? <CheckCircle className="w-4 h-4"/> : tx.status === 'pending' ? <Activity className="w-4 h-4 animate-pulse"/> : <XCircle className="w-4 h-4"/>}
                                {tx.status}
                              </span>
                            </td>
                            <td className="p-6 text-right pr-8">
                              {tx.status === 'pending' && tx.type === 'withdrawal' && (
                                <div className="flex justify-end gap-2">
                                  <button onClick={() => handleProcessWithdrawal(tx.id, true)} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-green-600/20 active:scale-95 transition-all">Approve</button>
                                  <button onClick={() => handleProcessWithdrawal(tx.id, false)} className="bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-600/20 active:scale-95 transition-all">Reject</button>
                                </div>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Settings Tab */}
              {activeTab === 'settings' && (
                <div className="bg-white rounded-[2rem] shadow-sm border border-gray-100 p-8 max-w-2xl mx-auto">
                  <div className="flex items-center gap-4 mb-8 border-b border-gray-100 pb-6">
                    <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center">
                      <Settings className="w-8 h-8 text-gray-400" />
                    </div>
                    <div>
                      <h2 className="text-2xl font-black text-gray-800 italic uppercase">System Core</h2>
                      <p className="text-gray-400 font-bold text-xs uppercase tracking-widest">Platform Configuration</p>
                    </div>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <label className="text-gray-600 text-xs font-black uppercase tracking-wider mb-2 block">Deposit UPI ID</label>
                      <input 
                        type="text" 
                        value={appSettings.upi_id}
                        onChange={(e) => setAppSettings({ ...appSettings, upi_id: e.target.value })}
                        placeholder="e.g. yourupi@oksbi" 
                        className="w-full px-6 py-4 bg-gray-50 border border-gray-200 rounded-2xl text-lg font-mono focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent transition-all"
                      />
                    </div>

                    <button 
                      onClick={handleSaveSettings}
                      className="w-full bg-red-600 hover:bg-red-500 text-white font-black uppercase tracking-widest py-5 rounded-2xl shadow-lg shadow-red-600/20 active:scale-95 transition-all"
                    >
                      Save Configuration
                    </button>
                  </div>
                </div>
              )}
            </>
          )}
        </main>
      </div>
    </div>
  );
}

