function getInitialCounter(sessionType: SessionType): number {
  const now = new Date();
  const startOfDay = new Date(now);
  startOfDay.setUTCHours(0, 0, 0, 0);
  const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
  return Math.floor(elapsedSeconds / SESSION_CONFIGS[sessionType].durationSeconds) + 1;
}

const INITIAL_COUNTERS: Record<SessionType, number> = {
  '30s': getInitialCounter('30s'),
  '1min': getInitialCounter('1min'),
  '3min': getInitialCounter('3min'),
  '5min': getInitialCounter('5min'),
  '10min': getInitialCounter('10min'),
};

args.old_string:
const INITIAL_COUNTERS: Record<SessionType, number> = {
  '30s': 100, '1min': 100, '3min': 100, '5min': 100, '10min': 100,
};
function generateSeedHistory(sessionType: SessionType, startCounter: number): GameResult[] {
  const results: GameResult[] = [];
  const now = Date.now();
  for (let i = 1; i <= 20; i++) {
    const counter = startCounter - i;
    const num = Math.floor(Math.random() * 10) as NumberValue;
    results.push({
      period: generatePeriod(sessionType, counter),
      number: num,
      color: getColorForNumber(num),
      big_small: getSizeForNumber(num),
      session_type: sessionType,
      timestamp: now - i * SESSION_CONFIGS[sessionType].durationSeconds * 1000,
    });
  }
  return results;
}

