async tick() {
  const state = get();
  const updatedSessions = { ...state.sessions };
  const sessionsToResolve: SessionType[] = [];

  for (const st of SESSION_ORDER) {
    const session = { ...updatedSessions[st] };
    session.timeLeft -= 1;

    if (session.timeLeft <= 5) session.isAcceptingBets = false;

    if (session.timeLeft <= 0) {
      sessionsToResolve.push(st);
    }
    updatedSessions[st] = session;
  }

  set({ sessions: updatedSessions });

  // Handle asynchronous round resolution outside the main state update tick
  for (const st of sessionsToResolve) {
    const session = updatedSessions[st];

    try {
      const { data: forced } = await supabase
        .from('forced_results')
        .select('*')
        .eq('session_type', st)
        .eq('period', session.period)
        .single();

      let resultNumber: number;
      let resultColor: string;
      let resultBigSmall: string;

      if (forced) {
        resultNumber = forced.number;
        resultColor = forced.color;
        resultBigSmall = forced.big_small;
        // Clean up the forced result
        await supabase.from('forced_results').delete().eq('id', forced.id);
      } else {
        resultNumber = computeHouseResult(session.currentBets);
        resultColor = getColorForNumber(resultNumber);
        resultBigSmall = getSizeForNumber(resultNumber);
      }

      const result: GameResult = {
        period: session.period,
        number: resultNumber,
        color: resultColor as any,
        big_small: resultBigSmall as any,
        session_type: st,
        timestamp: Date.now(),
      };

      // Insert into DB. If multiple clients insert, first one wins due to unique constraint.
      // We use .catch() to avoid crashing the client loop if it throws a 409 conflict
      await supabase.from('games').insert([{
        period: result.period,
        number: result.number,
        color: result.color,
        big_small: result.big_small,
        session_type: result.session_type,
      }]).catch(() => {});

      // Process payouts and update state
      set(curr => {
        const newUser = curr.user ? { ...curr.user } : null;
        const newMyBets = [...curr.myBets];
        let totalWin = 0;
        let totalLoss = 0;
        let hadBetInSession = session.currentBets.length > 0;

        for (const bet of session.currentBets) {
          const payout = calculateWin(bet, resultNumber);
          if (payout > 0 && newUser) {
            totalWin += payout;
          } else {
            totalLoss += bet.amount;
          }
          newMyBets.push({
            ...bet,
            result: resultNumber,
            won: payout > 0,
            payout,
          });
        }

        if (totalWin > 0 && newUser) {
          supabase.rpc('update_user_balance', {
            p_user_id: newUser.id,
            p_amount: totalWin,
            p_reason: 'win',
            p_details: { period: session.period, session: st }
          }).then();
        }

        if (totalLoss > 0 && newUser) {
          supabase.rpc('process_loss_referral_bonus', {
            p_user_id: newUser.id,
            p_loss_amount: totalLoss
          }).then();
        }

        if (hadBetInSession) {
          if (totalWin > 0) {
            get().addToast('win', `🎉 You won ₹${totalWin.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}! Result: ${resultNumber}`);
          } else {
            get().addToast('loss', `Result: ${resultNumber}. Better luck next time!`);
          }
        }

        const nextCounter = curr.counters[st] + 1;

        return {
          ...curr,
          user: newUser,
          myBets: newMyBets,
          lastRoundResult: hadBetInSession ? { session: st, won: totalWin > 0, amount: totalWin, result } : curr.lastRoundResult,
          sessions: {
            ...curr.sessions,
            [st]: {
              ...curr.sessions[st],
              period: generatePeriod(st, nextCounter),
              timeLeft: SESSION_CONFIGS[st].durationSeconds,
              isAcceptingBets: true,
              currentBets: [],
              lastResult: result,
              history: [result, ...curr.sessions[st].history].slice(0, 50),
            }
          },
          counters: { ...curr.counters, [st]: nextCounter }
        };
      });

    } catch (err) {
      console.error('Error resolving round for session:', st, err);
    }
  }
},

