import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  initialized: boolean;
  refreshProfile: (userId: string) => Promise<void>;
  initialize: () => Promise<void>;
  signOut: () => Promise<void>;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: false,
  initialized: false,

  refreshProfile: async (userId: string) => {
    // Only show loading if we don't have a profile yet
    if (!get().profile) set({ loading: true });

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) throw error;

      if (data) {
        set({ profile: data, loading: false });
        try {
          useGameStore.getState().syncUser({
            id: data.id,
            username: data.username,
            balance: data.balance,
            is_admin: data.is_admin
          });
        } catch (syncErr) {}
      }
    } catch (err) {
      console.error('Profile fetch failed:', err);
      set({ profile: null, loading: false });
    }
  },

  initialize: async () => {
    if (get().initialized) return;

    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (session?.user && !session.user.is_anonymous) {
        set({ user: session.user });
        await get().refreshProfile(session.user.id);
      }
    } catch (error) {
      console.error('Initial session fetch failed:', error);
    } finally {
      // Mark as initialized no matter what happened.
      set({ initialized: true, loading: false });
    }

    // Single source of truth listener
    supabase.auth.onAuthStateChange(async (event, session) => {
      // Sign in or Identity changed
      if ((event === 'SIGNED_IN' || event === 'USER_UPDATED') && session?.user) {
        set({ user: session.user });
        await get().refreshProfile(session.user.id);
      } 
      // Sign out
      else if (event === 'SIGNED_OUT') {
        set({ user: null, profile: null, loading: false });
        try { useGameStore.getState().syncUser(null); } catch(e){}
      }
      set({ initialized: true });
    });
  },

  signOut: async () => {
    try {
      set({ loading: true });
      await supabase.auth.signOut();

      // Safety: Wipe local storage keys
      Object.keys(localStorage).forEach(key => {
        if (key.includes('supabase.auth')) localStorage.removeItem(key);
      });
    } catch (err) {
      console.error('Sign out error:', err);
    } finally {
      set({ user: null, profile: null, loading: false });
      try { useGameStore.getState().syncUser(null); } catch(e){}
    }
  }
}));

