import { create } from 'zustand';
import { supabase } from '../lib/supabase';
import { useGameStore } from './gameStore';

interface AuthStore {
  user: any | null;
  profile: any | null;
  loading: boolean;
  initialized: boolean;
  refreshProfile: (userId: string) => Promise<void>;
  initialize: () => Promise<void>;
  signOut: () => Promise<void>;
}

export const useAuthStore = create<AuthStore>((set, get) => ({
  user: null,
  profile: null,
  loading: false, // Default to false
  initialized: false,

  refreshProfile: async (userId: string) => {
    // Only show loading if we really don't have a profile yet
    const currentProfile = get().profile;
    if (!currentProfile) set({ loading: true });

    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) throw error;

      if (data) {
        set({ profile: data, loading: false });
        try {
          useGameStore.getState().syncUser({
            id: data.id,
            username: data.username,
            balance: data.balance,
            is_admin: data.is_admin
          });
        } catch (syncErr) {}
      }
    } catch (err) {
      console.error('Profile fetch failed:', err);
      set({ profile: null, loading: false });
    }
  },

  initialize: async () => {
    // CRITICAL: If we are already initialized, NEVER show the loading screen again
    if (get().initialized) return;

    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (session?.user && !session.user.is_anonymous) {
        set({ user: session.user });
        await get().refreshProfile(session.user.id);
      }
    } catch (error) {
      console.error('Session check failed:', error);
    } finally {
      // Mark as initialized no matter what. The app is now ready to show either Login or Game.
      set({ initialized: true, loading: false });
    }

    // Listen for auth changes (Login/Logout)
    supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        set({ user: session.user });
        await get().refreshProfile(session.user.id);
      } else if (event === 'SIGNED_OUT') {
        set({ user: null, profile: null, loading: false });
        useGameStore.getState().syncUser(null);
      }
      set({ initialized: true });
    });
  },

    // Auth state listener
    supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'INITIAL_SESSION') return;

      try {
        if (session?.user && !session.user.is_anonymous) {
          set({ user: session.user, loading: true });
          await get().refreshProfile(session.user.id);
        } else {
          set({ user: null, profile: null });
        }
      } catch (err) {
        console.error('Auth listener crashed:', err);
        set({ user: null, profile: null });
      } finally {
        set({ loading: false });
      }
    });
  },

  signOut: async () => {
    try {
      set({ loading: true });
      await supabase.auth.signOut();
    } catch (err) {
      console.error('Sign out error:', err);
    } finally {
      set({ user: null, profile: null, loading: false });

      try {
        useGameStore.getState().syncUser(null);
      } catch (err) {
        // Silently catch in case game store is already unmounted
      }
    }
  }
}));

