resultDisplay.originalContent:
import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';
import { useGameStore } from '../store/gameStore';
import { Copy, Share2, Users, Wallet, TrendingUp, HelpCircle } from 'lucide-react';

export default function ReferralTab() {
  const { profile } = useAuthStore();
  const { addToast } = useGameStore();
  const [stats, setStats] = useState({
    totalReferred: 0,
    totalEarnings: 0,
    thisMonth: 0
  });
  const [referredUsers, setReferredUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (profile?.id) fetchReferralData();
  }, [profile]);

  const fetchReferralData = async () => {
    try {
      // 1. Fetch referral stats
      const { count } = await supabase
        .from('profiles')
        .select('*', { count: 'exact', head: true })
        .eq('referred_by', profile.id);

      const { data: earnings } = await supabase
        .from('referral_earnings')
        .select('amount, created_at')
        .eq('referrer_id', profile.id);

      const totalEarned = earnings?.reduce((sum, e) => sum + Number(e.amount), 0) || 0;

      const now = new Date();
      const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
      const monthEarned = earnings
        ?.filter(e => e.created_at >= firstDay)
        .reduce((sum, e) => sum + Number(e.amount), 0) || 0;

      setStats({
        totalReferred: count || 0,
        totalEarnings: totalEarned,
        thisMonth: monthEarned
      });

      // 2. Fetch list of referred users (anonymized)
      const { data: users } = await supabase
        .from('profiles')
        .select('username, created_at')
        .eq('referred_by', profile.id)
        .order('created_at', { ascending: false })
        .limit(10);

      if (users) setReferredUsers(users);
    } finally {
      setLoading(false);
    }
  };

  const referralLink = `${window.location.origin}/register?ref=${profile?.referral_code}`;

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    addToast('success', `${label} copied!`);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Invite Card */}
      <div className="bg-gradient-to-br from-red-600 to-red-800 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <Share2 size={120} />
        </div>

        <h3 className="text-2xl font-black italic mb-1 uppercase tracking-tight">Refer & Earn</h3>
        <p className="text-red-100 text-xs font-medium mb-6 opacity-80 uppercase tracking-widest">Share with friends and earn commission</p>

        <div className="space-y-4">
          <div className="bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl p-4">
            <p className="text-[10px] font-bold uppercase tracking-widest text-red-200 mb-2">My Referral Code</p>
            <div className="flex items-center justify-between">
              <span className="text-2xl font-black tracking-[0.3em] font-mono">{profile?.referral_code || '-------'}</span>
              <button 
                onClick={() => copyToClipboard(profile?.referral_code || '', 'Code')}
                className="bg-white text-red-600 px-4 py-2 rounded-xl font-black text-xs uppercase active:scale-95 transition-all"
              >
                Copy
              </button>
            </div>
          </div>

          <div className="bg-black/20 rounded-2xl p-4 flex items-center justify-between group">
            <div className="overflow-hidden mr-4">
              <p className="text-[10px] font-bold uppercase text-red-300 mb-1">Invite Link</p>
              <p className="text-[11px] font-mono opacity-60 truncate">{referralLink}</p>
            </div>
            <button 
              onClick={() => copyToClipboard(referralLink, 'Link')}
              className="p-2 hover:bg-white/10 rounded-full transition-colors"
            >
              <Copy size={18} />
            </button>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-3 gap-3">
        {[
          { label: 'Invited', value: stats.totalReferred, icon: Users, color: 'text-blue-500', bg: 'bg-blue-500/10' },
          { label: 'Total Earning', value: `₹${stats.totalEarnings.toFixed(0)}`, icon: Wallet, color: 'text-green-500', bg: 'bg-green-500/10' },
          { label: 'This Month', value: `₹${stats.thisMonth.toFixed(0)}`, icon: TrendingUp, color: 'text-amber-500', bg: 'bg-amber-500/10' },
        ].map((s, i) => (
          <div key={i} className="bg-white border border-gray-100 rounded-2xl p-3 text-center shadow-sm">
            <div className={`w-8 h-8 ${s.bg} ${s.color} rounded-lg flex items-center justify-center mx-auto mb-2`}>
              <s.icon size={16} />
            </div>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter mb-0.5">{s.label}</p>
            <p className="text-sm font-black text-gray-800">{s.value}</p>
          </div>
        ))}
      </div>

      {/* How it works */}
      <div className="bg-white rounded-3xl border border-gray-100 p-6 shadow-sm">
        <div className="flex items-center gap-2 mb-4">
          <HelpCircle size={18} className="text-red-600" />
          <h4 className="font-black uppercase italic text-sm text-gray-800">How it works?</h4>
        </div>
        <div className="space-y-4">
          {[
            { step: '01', title: 'Invite Friends', desc: 'Share your referral link or code with your friends.' },
            { step: '02', title: 'Friends Register', desc: 'When they sign up using your code, they become your subordinate.' },
            { step: '03', title: 'Earn Commission', desc: 'Get 10% bonus on their deposits & 5% on their game losses!' },
          ].map((s, i) => (
            <div key={i} className="flex gap-4">
              <span className="text-xl font-black text-red-100 leading-none">{s.step}</span>
              <div>
                <p className="text-xs font-bold text-gray-800 mb-0.5">{s.title}</p>
                <p className="text-[10px] text-gray-400 font-medium leading-relaxed">{s.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Subordinates List */}
      <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden shadow-sm">
        <div className="p-5 border-b border-gray-50 flex items-center justify-between">
          <h4 className="font-black uppercase italic text-sm text-gray-800">My Subordinates</h4>
          <span className="text-[10px] font-bold bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">Recent 10</span>
        </div>
        <div className="divide-y divide-gray-50">
          {referredUsers.length === 0 ? (
            <div className="p-10 text-center text-gray-400 text-xs font-medium italic">No subordinates yet. Start inviting!</div>
          ) : (
            referredUsers.map((u, i) => (
              <div key={i} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center font-bold text-gray-400 text-xs">
                    {u.username.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <p className="text-xs font-bold text-gray-800 uppercase italic">{u.username.substring(0, 3)}****{u.username.slice(-2)}</p>
                    <p className="text-[9px] text-gray-400 uppercase tracking-tighter">{new Date(u.created_at).toLocaleDateString()}</p>
                  </div>
                </div>
                <span className="text-[10px] font-bold text-green-600 bg-green-50 px-2 py-1 rounded-lg uppercase tracking-widest">Active</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

