import { useGameStore, GameResult } from '../store/gameStore';

function ColorDot({ color }: { color: GameResult['color'] }) {
  if (color === 'red-violet') {
    return (
      <div className="flex gap-0.5 items-center justify-center">
        <span className="w-3 h-3 rounded-full bg-red-500 inline-block" />
        <span className="w-3 h-3 rounded-full bg-violet-500 inline-block" />
      </div>
    );
  }
  if (color === 'green-violet') {
    return (
      <div className="flex gap-0.5 items-center justify-center">
        <span className="w-3 h-3 rounded-full bg-green-500 inline-block" />
        <span className="w-3 h-3 rounded-full bg-violet-500 inline-block" />
      </div>
    );
  }
  const colorMap = {
    green: 'bg-green-500',
    red: 'bg-red-500',
    violet: 'bg-violet-500',
  };
  return <span className={`w-4 h-4 rounded-full ${colorMap[color as 'green' | 'red' | 'violet']} inline-block`} />;
}

function NumberBall({ number, color }: { number: number; color: GameResult['color'] }) {
  let textColor = 'text-red-500';
  if (color === 'green' || color === 'green-violet') textColor = 'text-green-500';
  if (color === 'violet') textColor = 'text-violet-500';

  return (
    <span className={`font-black text-lg ${textColor}`}>{number}</span>
  );
}

function GameHistoryTable() {
  const { activeSession, sessions } = useGameStore();
  const history = sessions[activeSession].history;

  if (history.length === 0) {
    return (
      <div className="text-center py-8 text-gray-400 text-sm">
        No results yet for this session
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-sm">
        <thead>
          <tr className="bg-red-500 text-white">
            <th className="py-2 px-2 text-left font-semibold text-xs">Period</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Number</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Big Small</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Color</th>
          </tr>
        </thead>
        <tbody>
          {history.map((result, idx) => (
            <tr
              key={result.period}
              className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}
            >
              <td className="py-2.5 px-2 text-gray-500 font-mono text-xs">{result.period}</td>
              <td className="py-2.5 px-2 text-center">
                <NumberBall number={result.number} color={result.color} />
              </td>
              <td className="py-2.5 px-2 text-center text-gray-700 text-xs font-medium">
                {result.big_small}
              </td>
              <td className="py-2.5 px-2 text-center">
                <div className="flex justify-center">
                  <ColorDot color={result.color} />
                </div>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function MyHistoryTable() {
  const { myBets, activeSession } = useGameStore();
  const bets = myBets
    .filter(b => b.sessionType === activeSession)
    .reverse()
    .slice(0, 30);

  if (bets.length === 0) {
    return (
      <div className="text-center py-8 text-gray-400 text-sm">
        No bets placed in this session yet
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-sm">
        <thead>
          <tr className="bg-red-500 text-white">
            <th className="py-2 px-2 text-left font-semibold text-xs">Period</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Bet</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Amount</th>
            <th className="py-2 px-2 text-center font-semibold text-xs">Result</th>
          </tr>
        </thead>
        <tbody>
          {bets.map((bet, idx) => (
            <tr key={bet.id} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
              <td className="py-2.5 px-2 text-gray-500 font-mono text-xs">{bet.period}</td>
              <td className="py-2.5 px-2 text-center text-gray-700 text-xs font-medium capitalize">
                {bet.type === 'number' ? `#${bet.value}` : String(bet.value)}
              </td>
              <td className="py-2.5 px-2 text-center text-gray-700 text-xs">₹{bet.amount}</td>
              <td className="py-2.5 px-2 text-center text-xs font-bold">
                {bet.won === undefined ? (
                  <span className="text-yellow-500">Pending</span>
                ) : bet.won ? (
                  <span className="text-green-600">+₹{bet.payout?.toFixed(2)}</span>
                ) : (
                  <span className="text-red-500">Lost</span>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function ChartPlaceholder() {
  const { activeSession, sessions } = useGameStore();
  const history = sessions[activeSession].history.slice(0, 20).reverse();

  return (
    <div className="p-4">
      <div className="text-center text-gray-500 text-sm mb-4 font-medium">Last 20 Results — Color Chart</div>
      <div className="flex items-end gap-1 h-32 justify-center">
        {history.map((result, i) => {
          const color = result.color === 'green' || result.color === 'green-violet' ? 'bg-green-500' :
                        result.color === 'red' || result.color === 'red-violet' ? 'bg-red-500' :
                        'bg-violet-500';
          const height = (result.number + 1) * 11;
          return (
            <div key={i} className="flex flex-col items-center gap-1">
              <div
                className={`${color} rounded-t w-6 transition-all`}
                style={{ height: `${height}px` }}
                title={`${result.period}: ${result.number}`}
              />
              <span className="text-gray-400 text-[9px]">{result.number}</span>
            </div>
          );
        })}
      </div>
      <div className="flex justify-center gap-4 mt-4 text-xs text-gray-500">
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-green-500 inline-block" /> Green (1,3,7,9)</span>
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-red-500 inline-block" /> Red (2,4,6,8)</span>
        <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-full bg-violet-500 inline-block" /> Violet (0,5)</span>
      </div>
    </div>
  );
}

export default function GameHistory() {
  const { historyTab, setHistoryTab } = useGameStore();

  return (
    <div className="mx-3 mt-4 mb-4 rounded-2xl overflow-hidden shadow-sm border border-gray-100 bg-white">
      {/* Tab bar */}
      <div className="flex">
        <button
          onClick={() => setHistoryTab('game')}
          className={`flex-1 py-3 text-sm font-semibold transition-all ${
            historyTab === 'game'
              ? 'bg-red-500 text-white'
              : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
          } rounded-tl-2xl`}
        >
          Game history
        </button>
        <button
          onClick={() => setHistoryTab('chart')}
          className={`flex-1 py-3 text-sm font-semibold transition-all ${
            historyTab === 'chart'
              ? 'bg-red-500 text-white'
              : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
          }`}
        >
          Chart
        </button>
        <button
          onClick={() => setHistoryTab('my')}
          className={`flex-1 py-3 text-sm font-semibold transition-all ${
            historyTab === 'my'
              ? 'bg-red-500 text-white'
              : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
          } rounded-tr-2xl`}
        >
          My history
        </button>
      </div>

      {/* Content */}
      {historyTab === 'game' && <GameHistoryTable />}
      {historyTab === 'chart' && <ChartPlaceholder />}
      {historyTab === 'my' && <MyHistoryTable />}
    </div>
  );
}

