import React, { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { 
  ChevronLeft, ChevronRight, Search, Calendar, 
  Filter, X, Download, Loader2 
} from 'lucide-react';
import { cn } from '../utils/cn';

interface PaginatedTableProps {
  tableName: string;
  queryModifier?: (query: any) => any;
  columns: { key: string; label: string; render?: (row: any) => React.ReactNode }[];
  pageSize?: number;
  searchPlaceholder?: string;
  searchFields?: string[];
  dateField?: string;
  emptyMessage?: string;
  onDataLoaded?: (data: any[]) => void;
}

export default function PaginatedTable({
  tableName,
  queryModifier,
  columns,
  pageSize = 10,
  searchPlaceholder = "Search...",
  searchFields = [],
  dateField = "created_at",
  emptyMessage = "No records found",
  onDataLoaded
}: PaginatedTableProps) {
  const [data, setData] = useState<any[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState<'all' | 'today' | '7d' | '30d' | 'custom'>('30d');
  const [customRange, setCustomRange] = useState({ from: '', to: '' });
  const [showFilters, setShowFilters] = useState(false);

  // Use a ref for queryModifier to avoid infinite re-fetch loops if parent passes inline functions
  const queryModifierRef = useRef(queryModifier);
  useEffect(() => {
    queryModifierRef.current = queryModifier;
  }, [queryModifier]);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      let query = supabase
        .from(tableName)
        .select('*', { count: 'exact' });

      // Apply stable query modifier
      if (queryModifierRef.current) {
        query = queryModifierRef.current(query);
      }

      // Apply Search
      if (search && searchFields.length > 0) {
        const searchConditions = searchFields.map(field => `${field}.ilike.%${search}%`).join(',');
        query = query.or(searchConditions);
      }

      // Apply Date Filter
      const now = new Date();
      if (dateFilter === 'today') {
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
        query = query.gte(dateField, today);
      } else if (dateFilter === '7d') {
        const last7d = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 7).toISOString();
        query = query.gte(dateField, last7d);
      } else if (dateFilter === '30d') {
        const last30d = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 30).toISOString();
        query = query.gte(dateField, last30d);
      } else if (dateFilter === 'custom' && customRange.from && customRange.to) {
        query = query.gte(dateField, customRange.from).lte(dateField, customRange.to + 'T23:59:59');
      }

      // Pagination
      const from = (currentPage - 1) * pageSize;
      const to = from + pageSize - 1;

      query = query
        .order(dateField, { ascending: false })
        .range(from, to);

      const { data: result, count, error } = await query;

      if (error) throw error;

      setData(result || []);
      setTotalCount(count || 0);
      if (onDataLoaded) onDataLoaded(result || []);
    } catch (err) {
      console.error(`Error fetching ${tableName}:`, err);
    } finally {
      // Small delay to prevent flicker
      setTimeout(() => setLoading(false), 200);
    }
  }, [tableName, currentPage, pageSize, search, dateFilter, customRange, searchFields, dateField, onDataLoaded]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const totalPages = Math.ceil(totalCount / pageSize);

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setCurrentPage(1);
    fetchData();
  };

  const clearFilters = () => {
    setSearch('');
    setDateFilter('all');
    setCustomRange({ from: '', to: '' });
    setCurrentPage(1);
  };

  const exportToCSV = () => {
    if (data.length === 0) return;
    const headers = columns.map(col => col.label).join(',');
    const rows = data.map(row => 
      columns.map(col => {
        const val = row[col.key];
        return typeof val === 'object' ? JSON.stringify(val) : `"${val}"`;
      }).join(',')
    ).join('\n');

    const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows;
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${tableName}_export.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      {/* Header Controls */}
      <div className="flex flex-col md:flex-row gap-3">
        <form onSubmit={handleSearch} className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder={searchPlaceholder}
            className="w-full bg-white border border-gray-200 rounded-xl py-2.5 pl-10 pr-4 text-sm focus:outline-none focus:border-red-500 transition-colors"
          />
        </form>

        <div className="flex gap-2">
          <button 
            onClick={() => setShowFilters(!showFilters)}
            className={cn(
              "flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-black uppercase transition-all border",
              showFilters || dateFilter !== 'all' ? "bg-red-50 border-red-200 text-red-600" : "bg-white border-gray-200 text-gray-600"
            )}
          >
            <Filter size={14} />
            Filter
          </button>
          <button 
            onClick={exportToCSV}
            className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white border border-gray-200 text-gray-600 text-xs font-black uppercase hover:bg-gray-50 transition-all"
          >
            <Download size={14} />
            Export
          </button>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
        <div className="bg-gray-50 border border-gray-200 rounded-2xl p-4 space-y-4 animate-in fade-in slide-in-from-top-2">
          <div className="flex flex-wrap gap-2">
            {[
              { id: 'all', label: 'All Time' },
              { id: 'today', label: 'Today' },
              { id: '7d', label: 'Last 7 Days' },
              { id: '30d', label: 'Last 30 Days' },
              { id: 'custom', label: 'Custom Range' }
            ].map(btn => (
              <button
                key={btn.id}
                onClick={() => setDateFilter(btn.id as any)}
                className={cn(
                  "px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all",
                  dateFilter === btn.id ? "bg-red-600 text-white" : "bg-white border border-gray-200 text-gray-500"
                )}
              >
                {btn.label}
              </button>
            ))}
          </div>

          {dateFilter === 'custom' && (
            <div className="flex items-center gap-2">
              <input 
                type="date" 
                value={customRange.from}
                onChange={e => setCustomRange({...customRange, from: e.target.value})}
                className="bg-white border border-gray-200 rounded-lg p-2 text-xs font-bold" 
              />
              <span className="text-gray-400 text-xs">to</span>
              <input 
                type="date" 
                value={customRange.to}
                onChange={e => setCustomRange({...customRange, to: e.target.value})}
                className="bg-white border border-gray-200 rounded-lg p-2 text-xs font-bold" 
              />
            </div>
          )}

          <div className="flex justify-between items-center pt-2 border-t border-gray-200">
            <button onClick={clearFilters} className="text-[10px] font-black uppercase text-gray-400 hover:text-red-600 transition-colors">Clear All</button>
            <button 
              onClick={() => { setShowFilters(false); setCurrentPage(1); fetchData(); }}
              className="bg-gray-900 text-white px-4 py-1.5 rounded-lg text-[10px] font-black uppercase"
            >
              Apply Filters
            </button>
          </div>
        </div>
      )}

      {/* Table Content */}
      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden min-h-[300px] relative">
        {loading && (
          <div className="absolute inset-0 bg-white/80 backdrop-blur-[1px] z-50 flex items-center justify-center">
            <Loader2 className="w-8 h-8 text-red-600 animate-spin" />
          </div>
        )}

        {data.length === 0 && !loading ? (
          <div className="flex flex-col items-center justify-center h-64 text-gray-400 opacity-50">
            <Filter size={48} className="mb-4" />
            <p className="font-bold uppercase text-xs tracking-widest">{emptyMessage}</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-gray-50/50 border-b border-gray-100">
                <tr>
                  {columns.map(col => (
                    <th key={col.key} className="p-4 text-[10px] font-black uppercase text-gray-400 tracking-wider">
                      {col.label}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {data.map((row, idx) => (
                  <tr key={row.id || idx} className="hover:bg-gray-50/50 transition-colors">
                    {columns.map(col => (
                      <td key={col.key} className="p-4">
                        {col.render ? col.render(row) : row[col.key]}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination Bar */}
      {totalPages > 0 && (
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4 px-2 py-4 border-t border-gray-100">
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            Showing <span className="text-gray-900">{(currentPage-1)*pageSize + 1}</span> to <span className="text-gray-900">{Math.min(currentPage*pageSize, totalCount)}</span> of <span className="text-gray-900">{totalCount}</span> records
          </p>

          <div className="flex items-center gap-1">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="p-2 rounded-xl border border-gray-200 text-gray-400 disabled:opacity-30 hover:bg-gray-50 transition-all"
            >
              <ChevronLeft size={16} />
            </button>

            <div className="flex items-center gap-1">
              {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                let pageNum = 1;
                if (totalPages <= 5) {
                  pageNum = i + 1;
                } else {
                  if (currentPage <= 3) pageNum = i + 1;
                  else if (currentPage >= totalPages - 2) pageNum = totalPages - 4 + i;
                  else pageNum = currentPage - 2 + i;
                }

                if (pageNum < 1 || pageNum > totalPages) return null;

                return (
                  <button
                    key={pageNum}
                    onClick={() => handlePageChange(pageNum)}
                    className={cn(
                      "w-8 h-8 rounded-xl text-xs font-black transition-all",
                      currentPage === pageNum ? "bg-red-600 text-white shadow-lg shadow-red-600/20" : "bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                    )}
                  >
                    {pageNum}
                  </button>
                );
              })}
            </div>

            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="p-2 rounded-xl border border-gray-200 text-gray-400 disabled:opacity-30 hover:bg-gray-50 transition-all"
            >
              <ChevronRight size={16} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

