  useEffect(() => {
    if (!isLoading) fetchData(false);
  }, [currentPage, dateFilter, search]);

  const totalPages = Math.ceil(totalCount / pageSize);

  const handlePageChange = (page: number) => {
    if (page >= 1 && page <= totalPages) setCurrentPage(page);
