import { useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../store/authStore';

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: string;
  read: boolean;
  created_at: string;
}

export function useNotifications() {
  const { user } = useAuthStore();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (!user?.id) return;

    const fetchNotifications = async () => {
      const { data } = await supabase
        .from('user_notifications')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false })
        .limit(20);

      if (data) {
        setNotifications(data);
        setUnreadCount(data.filter(n => !n.read).length);
      }
    };

    fetchNotifications();

    const channel = supabase
      .channel('public:user_notifications')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'user_notifications', filter: `user_id=eq.${user.id}` },
        (payload) => {
          setNotifications(prev => [payload.new as Notification, ...prev].slice(0, 20));
          setUnreadCount(prev => prev + 1);
        }
      )
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'user_notifications', filter: `user_id=eq.${user.id}` },
        (payload) => {
          setNotifications(prev => prev.map(n => n.id === payload.new.id ? (payload.new as Notification) : n));
          setUnreadCount(prev => {
             // Calculate fresh unread count on update to be safe
             // Real implementation would rely on full state or ref, but this is simple enough if we trust the payload
             return prev; 
          });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id]);

  const markAsRead = async (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
    setUnreadCount(prev => Math.max(0, prev - 1));
    await supabase.from('user_notifications').update({ read: true }).eq('id', id);
  };

  const markAllAsRead = async () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
    setUnreadCount(0);
    await supabase.from('user_notifications').update({ read: true }).eq('user_id', user?.id).eq('read', false);
  };

  return { notifications, unreadCount, markAsRead, markAllAsRead };
}

import { useState } from 'react';
import { useAuthStore } from '../store/authStore';
import WalletModal from './WalletModal';
import NotificationsCenter from './NotificationsCenter';
import { Bell } from 'lucide-react';
import { useNotifications } from '../hooks/useNotifications';

export default function Header() {
  const { user, profile, signOut, refreshProfile } = useAuthStore();
  const [showWallet, setShowWallet] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const { unreadCount } = useNotifications();

  const initials = profile?.username?.substring(0, 2).toUpperCase() || 'GU';

  const handleRefresh = async () => {
    if (!user?.id || isRefreshing) return;
    setIsRefreshing(true);
    await refreshProfile(user.id);
    setTimeout(() => setIsRefreshing(false), 1000); // 1 second cooldown
  };

  return (
    <>
      <header className="bg-red-600 text-white p-4 sticky top-0 z-50 shadow-md">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center font-bold text-sm border border-white/30">
              {initials}
            </div>
            <div>
              <p className="text-xs text-red-100 opacity-80">Welcome,</p>
              <p className="text-sm font-bold leading-none">{profile?.username || 'Loading...'}</p>
            </div>
          </div>

          <div className="flex items-center gap-1.5">
            <button 
              onClick={() => setShowNotifications(true)}
              className="relative p-2 hover:bg-white/10 rounded-full transition-colors mr-1"
            >
              <Bell className="w-5 h-5 text-white/90" />
              {unreadCount > 0 && (
                <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-yellow-400 rounded-full border-2 border-red-600"></span>
              )}
            </button>

            <button
              onClick={handleRefresh}
              disabled={isRefreshing}
              className={`p-1.5 hover:bg-white/10 rounded-full transition-colors ${isRefreshing ? 'opacity-50 cursor-not-allowed' : ''}`}
              title="Refresh Balance"
            >
              <svg className={`w-4 h-4 ${isRefreshing ? 'animate-spin text-yellow-300' : 'text-white/80'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
            </button>

            <button 
              onClick={() => setShowWallet(true)}
              className="bg-black/20 hover:bg-black/30 transition-colors px-3 py-1.5 rounded-full flex items-center gap-2 border border-white/10"
            >
              <span className="text-yellow-400 font-bold text-sm">₹{(profile?.balance || 0).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
              <svg className="w-4 h-4 text-white/70" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" />
              </svg>
            </button>
          </div>
        </div>
      </header>

      {showWallet && <WalletModal onClose={() => setShowWallet(false)} />}
      {showNotifications && <NotificationsCenter onClose={() => setShowNotifications(false)} />}
    </>
  );
}

import React from 'react';
import { X, Check, Bell } from 'lucide-react';
import { useNotifications, Notification } from '../hooks/useNotifications';

interface NotificationsCenterProps {
  onClose: () => void;
}

export default function NotificationsCenter({ onClose }: NotificationsCenterProps) {
  const { notifications, unreadCount, markAsRead, markAllAsRead } = useNotifications();

  return (
    <div className="fixed inset-0 z-[70] flex justify-end">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      {/* Panel */}
      <div className="relative w-full max-w-sm bg-gray-50 h-full flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">
        <div className="bg-red-600 px-6 py-4 flex items-center justify-between text-white shadow-md">
          <div className="flex items-center gap-2">
            <Bell className="w-5 h-5" />
            <h2 className="font-black italic text-lg tracking-tight">Notifications</h2>
            {unreadCount > 0 && (
              <span className="bg-white text-red-600 text-[10px] font-black px-2 py-0.5 rounded-full ml-1">
                {unreadCount}
              </span>
            )}
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {unreadCount > 0 && (
          <div className="bg-white border-b border-gray-200 px-4 py-2 flex justify-end">
            <button 
              onClick={markAllAsRead}
              className="text-[10px] font-bold text-gray-500 hover:text-red-600 flex items-center gap-1 transition-colors uppercase tracking-wider"
            >
              <Check className="w-3 h-3" /> Mark all read
            </button>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {notifications.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400 gap-3 opacity-50">
              <Bell className="w-12 h-12" />
              <p className="text-xs font-bold uppercase tracking-widest">No notifications</p>
            </div>
          ) : (
            notifications.map((n) => (
              <div 
                key={n.id} 
                onClick={() => !n.read && markAsRead(n.id)}
                className={`p-4 rounded-2xl border transition-all cursor-pointer ${
                  n.read 
                    ? 'bg-white border-gray-100 opacity-70' 
                    : 'bg-red-50 border-red-100 shadow-sm shadow-red-100/50 relative overflow-hidden'
                }`}
              >
                {!n.read && <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-500" />}
                <div className="flex items-start justify-between gap-4 mb-1">
                  <h4 className={`text-sm font-black ${n.read ? 'text-gray-700' : 'text-red-700'}`}>
                    {n.title}
                  </h4>
                  <span className="text-[9px] font-bold text-gray-400 whitespace-nowrap uppercase tracking-tighter">
                    {new Date(n.created_at).toLocaleDateString()}
                  </span>
                </div>
                <p className="text-xs text-gray-600 font-medium leading-relaxed">{n.message}</p>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

