      return null;
    }
  }

  if (!user) {
    return (
      <>
        <AuthPage />
        <ToastContainer />
      </>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'wingo':
        return (
          <div className="pb-24">
            <CountdownPanel />
            <BettingPanel />
            <CurrentBets />
            <GameHistory />
