            lastRoundResult: hadBetInSession ? { session: st, won: totalWin > 0, amount: totalWin, result } : curr.lastRoundResult,
            sessions: {
              ...curr.sessions,
              [st]: {
                ...curr.sessions[st],
                period: generatePeriod(st, correctCounter),
                timeLeft: correctTimeLeft,
                isAcceptingBets: correctTimeLeft > 5,
                isResolving: false,
                currentBets: [],
                lastResult: result,
                history: [result, ...curr.sessions[st].history].slice(0, 50),
              }
            },
            counters: { ...curr.counters, [st]: correctCounter }
          };
        });
      } catch (err) {
        console.error('Error resolving round for session:', st, err);
        set(curr => ({
          sessions: {
            ...curr.sessions,
            [st]: {
              ...curr.sessions[st],
              isResolving: false,
            }
          }
        }));
      }
    }
  }
}));

