try {
  // Use Promise.race to enforce a 10-second timeout on the DB resolution
  const fetchPromise = supabase
    .from('forced_results')
    .select('*')
    .eq('session_type', st)
    .eq('period', session.period)
    .limit(1);

  const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error('DB Timeout')), 10000));

  const { data: forcedData, error: forcedError } = (await Promise.race([fetchPromise, timeoutPromise])) as any;

  if (forcedError) {
    console.error('Error checking forced results:', forcedError);
  }

  const forced = forcedData && forcedData.length > 0 ? forcedData[0] : null;

  let resultNumber: number;
  let resultColor: string;
  let resultBigSmall: string;

  if (forced) {
    resultNumber = forced.number;
    resultColor = forced.color;
    resultBigSmall = forced.big_small;
    // Clean up the forced result without awaiting so we don't block
    supabase.from('forced_results').delete().eq('id', forced.id).catch(() => {});
  } else {
    resultNumber = computeHouseResult(session.currentBets);
    resultColor = getColorForNumber(resultNumber);
    resultBigSmall = getSizeForNumber(resultNumber);
  }

  const result: GameResult = {
    period: session.period,
    number: resultNumber,
    color: resultColor as any,
    big_small: resultBigSmall as any,
    session_type: st,
    timestamp: Date.now(),
  };

  // Insert into DB. If multiple clients insert, first one wins due to unique constraint.
  const { error: insertError } = await supabase.from('games').insert([{
    period: result.period,
    number: result.number,
    color: result.color,
    big_small: result.big_small,
    session_type: result.session_type,
  }]);

  if (insertError && insertError.code !== '23505') {
    console.error('Failed to save game result:', insertError);
  }

  // Process payouts and update state
  set(curr => {
    const newUser = curr.user ? { ...curr.user } : null;
    const newMyBets = [...curr.myBets];
    let totalWin = 0;
    let totalLoss = 0;
    let hadBetInSession = session.currentBets.length > 0;

    for (const bet of session.currentBets) {
      const payout = calculateWin(bet, resultNumber);
      if (payout > 0 && newUser) {
        totalWin += payout;
      } else {
        totalLoss += bet.amount;
      }
      newMyBets.push({
        ...bet,
        result: resultNumber,
        won: payout > 0,
        payout,
      });
    }

    if (totalWin > 0 && newUser) {
      supabase.rpc('update_user_balance', {
        p_user_id: newUser.id,
        p_amount: totalWin,
        p_reason: 'win',
        p_details: { period: session.period, session: st }
      }).then();
    }

    if (totalLoss > 0 && newUser) {
      supabase.rpc('process_loss_referral_bonus', {
        p_user_id: newUser.id,
        p_loss_amount: totalLoss
      }).then();
    }

    if (hadBetInSession) {
      if (totalWin > 0) {
        get().addToast('win', `🎉 You won ₹${totalWin.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}! Result: ${resultNumber}`);
      } else {
        get().addToast('loss', `Result: ${resultNumber}. Better luck next time!`);
      }
    }

    const { durationSeconds } = SESSION_CONFIGS[st];
    const now = new Date();
    const startOfDay = new Date(now);
    startOfDay.setUTCHours(0, 0, 0, 0);
    const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
    const correctCounter = Math.floor(elapsedSeconds / durationSeconds) + 1;
    const correctTimeLeft = durationSeconds - (elapsedSeconds % durationSeconds);

    return {
      ...curr,
      user: newUser,
      myBets: newMyBets,
      lastRoundResult: hadBetInSession ? { session: st, won: totalWin > 0, amount: totalWin, result } : curr.lastRoundResult,
      sessions: {
        ...curr.sessions,
        [st]: {
          ...curr.sessions[st],
          period: generatePeriod(st, correctCounter),
          timeLeft: correctTimeLeft,
          isAcceptingBets: correctTimeLeft > 5,
          isResolving: false,
          currentBets: [],
          lastResult: result,
          history: [result, ...curr.sessions[st].history].slice(0, 50),
        }
      },
      counters: { ...curr.counters, [st]: correctCounter }
    };
  });

} catch (err) {
  console.error('Error resolving round for session:', st, err);
  // CRITICAL SAFETY NET: Even if resolving fails (DB crash/timeout), we MUST fast-forward the state
  // to real-time so the UI never freezes at 00:00 permanently.
  set(curr => {
    const { durationSeconds } = SESSION_CONFIGS[st];
    const now = new Date();
    const startOfDay = new Date(now);
    startOfDay.setUTCHours(0, 0, 0, 0);
    const elapsedSeconds = Math.floor((now.getTime() - startOfDay.getTime()) / 1000);
    const correctCounter = Math.floor(elapsedSeconds / durationSeconds) + 1;
    const correctTimeLeft = durationSeconds - (elapsedSeconds % durationSeconds);

    return {
      ...curr,
      sessions: {
        ...curr.sessions,
        [st]: {
          ...curr.sessions[st],
          period: generatePeriod(st, correctCounter),
          timeLeft: correctTimeLeft,
          isAcceptingBets: correctTimeLeft > 5,
          isResolving: false,
          currentBets: [],
        }
      },
      counters: { ...curr.counters, [st]: correctCounter }
    };
  });
}

